external_knowledge:
- "troubled batteries" refers to battery units that have generated alerts (non-null alert type);
- "specific location" refers to location ID 1;
- "raised some kind of alarm" means that there is an alert type registered for these units;
- "names" in this context refers to the unit IDs.

sql:
SELECT unit_id, location_id
FROM battery_data
WHERE temperatures > 30 AND temperatures < 50;

SELECT unit_id 
FROM battery_units 
WHERE capacity = (SELECT MAX(capacity) FROM battery_units);

external_knowledge:
- 'power cells' refers to battery units;
- 'total charge currents' refers to the aggregated charge currents for each battery unit;
- The 'serial numbers' are used to uniquely identify each battery unit.

sql:
SELECT AVG(voltages) AS average_voltages
FROM battery_data
WHERE unit_id = 0 AND location_id = 2;

SELECT bu.unit_id, bu.model
FROM battery_units bu
WHERE bu.state_of_health > (
    SELECT AVG(state_of_health)
    FROM battery_units
) AND bu.unit_id IN (
    SELECT a.unit_id
    FROM alerts a
    WHERE a.alert_type = 'High Temperature'
);

SELECT "capacity", "state_of_health"
FROM "battery_units"
WHERE "unit_id" = 0 AND "state_of_health" < 0.5;
